import React, { useState } from "react";
import axios from "axios";
import "./ChatBox.css";
import MapView from "./MapView";

function ChatBox() {

  const [query, setQuery] = useState("");
  const [persons, setPersons] = useState(1);

  const [response, setResponse] = useState({
    ai_response: "",
    budget: {},
    recommendations: [],
    safety: {},
    itinerary: []
  });

  const sendQuery = async () => {

    try {

      const res = await axios.post(
        "http://127.0.0.1:8000/chat",
        {
          query,
          persons
        }
      );

      setResponse(res.data);

    } catch (error) {

      console.log(error);
      alert("Backend connection failed");
    }
  };

  return (

    <div className="container">

      <h1>🇮🇳 India AI Travel Planner</h1>

      <textarea
        placeholder="Example: Plan 3 days Goa trip under 20000"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
      />

      <input
        type="number"
        value={persons}
        onChange={(e) => setPersons(e.target.value)}
      />

      <button onClick={sendQuery}>
        Plan Trip
      </button>

      <div className="response">

        <h2>🤖 AI Response</h2>
        <p>{response.ai_response}</p>

        <h2>💰 Budget</h2>

        <p>Hotel: ₹{response.budget.hotel}</p>
        <p>Food: ₹{response.budget.food}</p>
        <p>Transport: ₹{response.budget.transport}</p>
        <p>Total: ₹{response.budget.total}</p>

        <h2>📍 Recommended Places</h2>

        {
          response.recommendations &&
          response.recommendations.map((place, index) => (

            <div className="card" key={index}>

              <h3>{place.name}</h3>

              <p><b>City:</b> {place.city}</p>

              <p><b>State:</b> {place.state}</p>

              <p><b>Type:</b> {place.type}</p>

              <p><b>Total Budget:</b> ₹{place.total_budget}</p>

              <p><b>Women Safety:</b> {place.women_safe}</p>

              <p><b>Safety Score:</b> {place.safety_score}</p>

              <p><b>Crowd Level:</b> {place.crowd_level}</p>

              <p><b>Best Time:</b> {place.best_time}</p>

              <p><b>Avoid Area:</b> {place.avoid_area}</p>

              <p>🚆 Railway: {place.railway_distance} km</p>

              <p>🚌 Bus Stand: {place.bus_distance} km</p>

              <p>✈ Airport: {place.airport_distance} km</p>

              <MapView
                lat={place.lat}
                lng={place.lng}
                name={place.name}
              />

            </div>
          ))
        }

        <h2>🛡 Safety</h2>

        <p>Women Safety: {response.safety.women_safety}</p>

        <p>Child Friendly: {response.safety.child_friendly}</p>

        <p>Night Risk: {response.safety.night_risk}</p>

        <h2>🗓 Itinerary</h2>

        {
          response.itinerary &&
          response.itinerary.map((day, index) => (
            <p key={index}>{day}</p>
          ))
        }

      </div>

    </div>
  );
}

export default ChatBox;
